    public static int addOne(int x) {
        int m = 1;
        // Flip all the set bits (trailing 1s) until we find a 0.
        while ((x & m) != 0) {
            x ^= m;   // Toggle the bit.
            m <<= 1;  // Move to the next bit.
        }
        // Toggle the first 0 bit (or an extra bit if x was all 1s).
        x ^= m;
        return x;
    }

