    public static int calcAngle(int h, int m) {
        // Validate input
        if (h < 0 || m < 0 || h > 12 || m > 60) {
            System.out.println("Wrong input");
        }
        // Handle edge cases
        if (h == 12) {
            h = 0;
        }
        if (m == 60) {
            m = 0;
        }
        // Calculate angles
        int hourAngle   = (int) (0.5 * (h * 60 + m)); // 0.5 degrees per minute
        int minuteAngle = 6 * m;                      // 6 degrees per minute
        // Find the difference
        int angle = Math.abs(hourAngle - minuteAngle);
        // Return the smaller angle
        return Math.min(360 - angle, angle);
    }

