    public static int ceilSearch(int[] arr, int low, int high, int x) {
        // If x is less than or equal to the first element,
        // arr[low] is the ceiling.
        if (x <= arr[low]) {
            return low;
        }
        // If x is larger than the last element, ceiling doesn’t exist.
        if (x > arr[high]) {
            return -1;
        }
        // Binary search logic
        int mid = (low + high) / 2;
        // If x is exactly at mid, mid is the ceiling.
        if (arr[mid] == x) {
            return mid;
        }
        // If mid element is less than x, ceiling must be in the right subarray
        if (arr[mid] < x) {
            // Check if the next element is the ceiling
            if (mid + 1 <= high && x <= arr[mid + 1]) {
                return mid + 1;
            }
            // Recurse into the right subarray
            return ceilSearch(arr, mid + 1, high, x);
        } else { // arr[mid] > x
            // If the previous element is less than x, mid is the ceiling
            if (mid - 1 >= low && x > arr[mid - 1]) {
                return mid;
            }
            // Recurse into the left subarray
            return ceilSearch(arr, low, mid - 1, x);
        }
    }

