    public static boolean halfDiagonalSums(int[][] mat, int n) {
        int diag1Left  = 0; // main-diagonal, rows   0 … n/2-1
        int diag1Right = 0; // main-diagonal, rows  n/2+1 … n-1
        int diag2Left  = 0; // anti-diagonal, rows  0 … n/2-1
        int diag2Right = 0; // anti-diagonal, rows n/2+1 … n-1
        int i = 0;
        int j = n - 1;      // column index for anti-diagonal
        while (i < n) {
            if (i < n / 2) {                // upper half
                diag1Left  += mat[i][i];
                diag2Left  += mat[j][i];    // (row = j, col = i)
            } else if (i > n / 2) {         // lower half
                diag1Right += mat[i][i];
                diag2Right += mat[j][i];
            }
            i++;
            j--;
        }
        return (diag1Left  == diag2Right) &&
               (diag2Right == diag2Left)  &&
               (diag1Right == diag2Left)  &&
               (diag2Right == mat[n / 2][n / 2]);
    }

