    public static boolean isDivisible999(String num) {
        int n = num.length();
        // Special-case for the single digit 0
        if (n == 1 && num.charAt(0) == '0') {
            return true;
        }
        /*  Make the length a multiple of 3 by adding leading zero(s)
            so that we can process the digits in groups of three.  */
        if (n % 3 == 1) {
            num = "00" + num;
            n += 2;
        } else if (n % 3 == 2) {
            num = "0" + num;
            n += 1;
        }
        /*  Sum the numeric value of every 3-digit group (from left to right).
            For each group abc => value = a*100 + b*10 + c  */
        int gSum = 0;
        for (int i = 0; i < n; i += 3) {
            int group = 0;
            group += (num.charAt(i)     - '0') * 100;
            group += (num.charAt(i + 1) - '0') * 10;
            group += (num.charAt(i + 2) - '0');
            gSum += group;
        }
        // If the obtained sum has more than three digits, repeat the process.
        if (gSum > 1000) {
            return isDivisible999(String.valueOf(gSum));
        }
        // Finally, the number is divisible by 999 iff the 3-digit sum equals 999
        return gSum == 999;
    }

