        if (s == null) {
            return false;             // simple null‐guard
        }
        // Immediate acceptance if length ≥ 10
        if (s.length() >= 10) {
            return true;
        }
        int n = s.length();
        // Try every possible way to split s into 4 non-empty contiguous substrings
        for (int i = 1; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                for (int k = j + 1; k < n; k++) {
                    String s1 = s.substring(0, i);
                    String s2 = s.substring(i, j);
