    public static boolean areConsecutive(int[] arr, int n) {
        if (n < 1) {
            return false;
        }
        // Find minimum and maximum values in the array
        int min = arr[0];
        int max = arr[0];
        for (int i = 1; i < n; i++) {
            if (arr[i] < min) {
                min = arr[i];
            }
            if (arr[i] > max) {
                max = arr[i];
            }
        }
        // Check if range fits the expected size
        if (max - min + 1 == n) {
            boolean[] visited = new boolean[n];
            for (int i = 0; i < n; i++) {
                int index = arr[i] - min;
                if (visited[index]) {  // duplicate found
                    return false;
                }
                visited[index] = true;
            }
            return true;
        }
        return false;
    }

