    public static boolean canRepresentBST(int[] pre, int n) {
        Stack<Integer> stack = new Stack<>();
        int root = Integer.MIN_VALUE;
        for (int i = 0; i < n; i++) {
            // If we encounter a value smaller than the last popped root,
            // the sequence cannot represent a BST.
            if (pre[i] < root) {
                return false;
            }
            // Remove all elements smaller than current element
            // and update root to the last popped element.
            while (!stack.isEmpty() && stack.peek() < pre[i]) {
                root = stack.pop();
            }
            // Push the current element to stack.
            stack.push(pre[i]);
        }
        return true;
    }

