    public static int isChangeable(int[] notes, int n) {
        int fiveCount = 0;  // number of ₹5 notes available
        int tenCount  = 0;  // number of ₹10 notes available
        for (int i = 0; i < n; i++) {
            if (notes[i] == 5) {                 // Customer pays with ₹5
                fiveCount++;
            } else if (notes[i] == 10) {         // Customer pays with ₹10
                if (fiveCount > 0) {
                    fiveCount--;                 // give back one ₹5 as change
                    tenCount++;                  // now we have an extra ₹10
                } else {
                    return 0;                    // cannot provide change
                }
            } else {                             // Customer pays with ₹20
                // Prefer giving one ₹10 and one ₹5 as change when possible
                if (fiveCount > 0 && tenCount > 0) {
                    fiveCount--;
                    tenCount--;
                } 
                // Otherwise, give three ₹5 notes as change
                else if (fiveCount >= 3) {
                    fiveCount -= 3;
                } 
                // No suitable combination to provide change
                else {
                    return 0;
                }
            }
        }
        return 1;                                // successfully provided change to everyone
    }

