    public static boolean checkDivisibility(String num) {
        int length = num.length();
        // Special case: the number “0” is divisible by every integer.
        if (length == 1 && num.charAt(0) == '0') {
            return true;
        }
        /*  Make the length a multiple of 3 by appending zeros on the right.
            This guarantees we can safely access i, i-1 and i-2 in the loop
            below without any additional bounds checking.               */
        if (length % 3 == 1) {
            num += "00";
            length += 2;
        } else if (length % 3 == 2) {
            num += "0";
            length += 1;
        }
        long sum = 0;   // will hold the alternating sum of 3-digit groups
        int  p   = 1;   // +1, -1, +1, -1, ...
        for (int i = length - 1; i >= 0; i -= 3) {
            int group = 0;
            group +=  (num.charAt(i)   - '0');        // units
            group += ((num.charAt(i-1) - '0') * 10);  // tens
            group += ((num.charAt(i-2) - '0') * 100); // hundreds
            sum += group * p;
            p *= -1;  // flip the sign for the next group
        }
        sum = Math.abs(sum);
        return (sum % 13 == 0);
    }

