    public static boolean isPerfectSquare(int n) {
        if (n < 0) {
            return false;  // negative numbers cannot be perfect squares
        }
        int i = 1;      // current odd number
        int sum = 0;    // cumulative sum of odd numbers
        while (sum < n) {
            sum += i;
            if (sum == n) {
                return true;
            }
            i += 2;     // move to next odd number
        }
        return false;    // sum has exceeded n, so n is not a perfect square
    }

