    public static boolean check(String s1, String s2) {
        int n = s1.length();
        int m = s2.length();
        // dp[i][j] is true if the first i characters of s1
        // can be transformed to match the first j characters of s2.
        boolean[][] dp = new boolean[n + 1][m + 1];
        dp[0][0] = true;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= m; j++) {
                if (!dp[i][j]) {
                    continue;
                }
                char c1 = s1.charAt(i);
                // Option 1: Try to match s1[i] (possibly upper-cased) with s2[j]
                if (j < m && Character.toUpperCase(c1) == s2.charAt(j)) {
                    dp[i + 1][j + 1] = true;
                }
                // Option 2: Delete the character if it is lowercase
                if (!Character.isUpperCase(c1)) {
                    dp[i + 1][j] = true;
                }
            }
        }
        return dp[n][m];
    }

