    static boolean isPossible(int n, int index, int modulo, int M, int[] arr, int[][] dp) {
        // Normalize modulo to keep it within [0, M-1]
        modulo = ((modulo % M) + M) % M;
        // Base case: all elements are considered
        if (index == n) {
            return modulo == 0;
        }
        // If the value has already been computed, return it
        if (dp[index][modulo] != -1) {
            return dp[index][modulo] == 1;
        }
        // Recurse by adding the current element
        boolean placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
        // Recurse by subtracting the current element
        boolean placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
        // Final result for this state
        boolean res = placeAdd || placeMinus;
        // Store the result in dp table (1 for true, 0 for false)
        dp[index][modulo] = res ? 1 : 0;
        return res;
    }

