    public static boolean isDivisible7(String num) {
        int n = num.length();
        // Edge-case guard (mirrors the odd Python check:  n == 0 and num[0] == '\n')
        if (n == 0) {
            return true;              // treat empty string as divisible (same as Python’s early return 1)
        }
        // Pad with zeroes so that the length becomes a multiple of 3
        StringBuilder sb = new StringBuilder(num);
        if (n % 3 == 1) {
            sb.append("00");
            n += 2;
        } else if (n % 3 == 2) {
            sb.append('0');
            n += 1;
        }
        num = sb.toString();
        long gSum = 0;                // alternating sum of the 3-digit groups
        int  sign = 1;                // corresponds to variable p in the Python code
        // Process the string from right to left, three digits at a time
        for (int i = n - 1; i >= 0; i -= 3) {
            int units     = num.charAt(i)     - '0';
            int tens      = num.charAt(i - 1) - '0';
            int hundreds  = num.charAt(i - 2) - '0';
            int group = hundreds * 100 + tens * 10 + units;   // value of this 3-digit group
            gSum += group * sign;                             // add or subtract, depending on position
            sign *= -1;                                       // flip the sign for the next group
        }
        return gSum % 7 == 0;
    }

