    public static void spiralFill(int m, int n, int[][] a) {
        int val = 1;     // value to write
        int k = 0;       // starting row index
        int l = 0;       // starting column index
        while (k < m && l < n) {
            /* 1. Fill the top row (left → right) */
            for (int i = l; i < n; i++) {
                a[k][i] = val++;
            }
            k++;  // move starting row downward
            /* 2. Fill the rightmost column (top → bottom) */
            for (int i = k; i < m; i++) {
                a[i][n - 1] = val++;
            }
            n--;  // shrink right boundary
            /* 3. Fill the bottom row if any (right → left) */
            if (k < m) {
                for (int i = n - 1; i >= l; i--) {
                    a[m - 1][i] = val++;
                }
                m--;  // move bottom boundary upward
            }
            /* 4. Fill the leftmost column if any (bottom → top) */
            if (l < n) {
                for (int i = m - 1; i >= k; i--) {
                    a[i][l] = val++;
                }
                l++;  // move left boundary rightward
            }
        }
    }

