    public static String decimalToBinary(double num, int k_prec) {
        StringBuilder binary = new StringBuilder();
        /* --------- Integral part --------- */
        long integral = (long) num;          // Extract integral part
        double fractional = num - integral;  // Extract fractional part
        // Handle integral part conversion
        if (integral == 0) {
            binary.append('0');
        } else {
            StringBuilder temp = new StringBuilder();
            while (integral > 0) {
                long rem = integral % 2;
                temp.append(rem);       // Collect remainders (LSB to MSB)
                integral /= 2;
            }
            binary.append(temp.reverse());   // Reverse to get MSB -> LSB
        }
        binary.append('.');   // Binary point
        /* --------- Fractional part --------- */
        while (k_prec-- > 0) {
            fractional *= 2;
            int fractBit = (int) fractional;
            if (fractBit == 1) {
                fractional -= fractBit;
                binary.append('1');
            } else {
                binary.append('0');
            }
        }
        return binary.toString();
    }

