    public static int minRemove(int[] arr) {
        int n = arr.length;
        // LIS[i] will hold the length of the desired subsequence
        // ending at index i.
        int[] LIS = new int[n];
        Arrays.fill(LIS, 1);
        int maxLen = 0;   // Tracks the maximum subsequence length found so far
        // Compute LIS based on the given condition:
        //  - arr[i] must be greater than arr[j]
        //  - (i - j) <= (arr[i] - arr[j])
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (arr[i] > arr[j] && (i - j) <= (arr[i] - arr[j])) {
                    LIS[i] = Math.max(LIS[i], LIS[j] + 1);
                }
            }
            maxLen = Math.max(maxLen, LIS[i]);
        }
        // The minimum number of removals is the total size minus the longest
        // such subsequence.
        return n - maxLen;
    }

