    public static long possibleStrings(int n, int r, int b, int g) {
        // Build the "fact" array (note: it’s actually a running sum, not factorial)
        long[] fact = new long[n + 1];
        fact[0] = 1;
        for (int i = 1; i <= n; i++) {
            fact[i] = fact[i - 1] + i;
        }
        int left = n - (r + g + b);
        long sum = 0;
        for (int i = 0; i <= left; i++) {
            for (int j = 0; j <= left - i; j++) {
                int k = left - (i + j);
                long denominator = fact[i + r] + fact[j + b] + fact[k + g];
                // Division followed by truncation toward zero (mimics Python's int())
                long value = (long) ((double) fact[n] / denominator);
                sum += value;
            }
        }
        return sum;
    }

