    public static long countPS(String str) {
        int n = str.length();
        if (n == 0) return 0;
        /* dp[i][j]   : stores the count of palindromic substrings
                        in str[i..j] */
        long[][] dp = new long[n][n];
        /* P[i][j]    : true if str[i..j] is a palindrome, else false */
        boolean[][] P = new boolean[n][n];
        // All length‐1 substrings are palindromes
        for (int i = 0; i < n; i++) {
            P[i][i] = true;
        }
        // Check for substring of length 2
        for (int i = 0; i < n - 1; i++) {
            if (str.charAt(i) == str.charAt(i + 1)) {
                P[i][i + 1] = true;
                dp[i][i + 1] = 1;   // one palindrome of length 2
            }
        }
        // Check for lengths greater than 2
        for (int gap = 2; gap < n; gap++) {
            for (int i = 0; i < n - gap; i++) {
                int j = i + gap;
                // Check if str[i..j] is palindrome
                if (str.charAt(i) == str.charAt(j) && P[i + 1][j - 1]) {
                    P[i][j] = true;
                }
                // Update count using inclusion–exclusion
                if (P[i][j]) {
                    dp[i][j] = dp[i][j - 1] + dp[i + 1][j] + 1 - dp[i + 1][j - 1];
                } else {
                    dp[i][j] = dp[i][j - 1] + dp[i + 1][j] - dp[i + 1][j - 1];
                }
            }
        }
        return dp[0][n - 1];
    }

