        // Extra padding (+2) to match the Python allocation
        int[][] cps = new int[N + 2][N + 2];
        // Every single character is a palindrome of length 1
        for (int i = 0; i < N; i++) {
            cps[i][i] = 1;
        }
        // Build the DP table
        for (int L = 2; L <= N; L++) {          // L is the current substring length
            for (int i = 0; i < N; i++) {       // i is the starting index
                int k = L + i - 1;              // k is the ending index
