    public static int countDecodingDP(String digits, int n) {
        // Edge cases
        if (digits == null || n == 0 || digits.length() == 0) {
            return 0;
        }
        if (digits.charAt(0) == '0') {
            return 0;
        }
        int[] count = new int[n + 1];
        count[0] = 1; // Empty string has one way to be decoded
        count[1] = 1; // Single non-zero digit has exactly one decoding
        for (int i = 2; i <= n; i++) {
            count[i] = 0;
            // If the current (i-1)th digit is not '0', it can be decoded on its own
            if (digits.charAt(i - 1) > '0') {
                count[i] = count[i - 1];
            }
            // Check if the last two digits form a valid character ('10' to '26')
            char prev = digits.charAt(i - 2);
            char curr = digits.charAt(i - 1);
            if (prev == '1' || (prev == '2' && curr < '7')) {
                count[i] += count[i - 2];
            }
        }
        return count[n];
    }

