    public static long countWords(String s) {
        int len = s.length();
        long count = 1;
        // Handle single–character string
        if (len == 1) {
            return count;
        }
        // Compare first two characters
        if (s.charAt(0) == s.charAt(1)) {
            count *= 1;
        } else {
            count *= 2;
        }
        // Handle characters from index 1 to len-2
        for (int j = 1; j < len - 1; j++) {
            char prev = s.charAt(j - 1);
            char curr = s.charAt(j);
            char next = s.charAt(j + 1);
            if (curr == prev && curr == next) {
                count *= 1;
            } else if (curr == prev || curr == next || prev == next) {
                count *= 2;
            } else {
                count *= 3;
            }
        }
        // Compare the last two characters
        if (s.charAt(len - 1) == s.charAt(len - 2)) {
            count *= 1;
        } else {
            count *= 2;
        }
        return count;
    }

