    public static String decode(String str) {
        Stack<Integer> integerStack = new Stack<>();
        Stack<Character> stringStack = new Stack<>();
        for (int i = 0; i < str.length(); i++) {
            char ch = str.charAt(i);
            /* If current character is a digit, build the full number (could be more than 1 digit). */
            if (Character.isDigit(ch)) {
                int count = 0;
                /* Handle multi-digit numbers. */
                while (i < str.length() && Character.isDigit(str.charAt(i))) {
                    count = count * 10 + (str.charAt(i) - '0');
                    i++;
                }
                /* Adjust index because for-loop will increment i once more. */
                i--;
                integerStack.push(count);
            } else if (ch == ']') {
                /* Start to build the string to repeat. */
                String temp = "";
                int count = 0;
                if (!integerStack.isEmpty()) {
                    count = integerStack.pop();
                }
                /* Pop characters until matching '['. */
                while (!stringStack.isEmpty() && stringStack.peek() != '[') {
                    temp = stringStack.pop() + temp;
                }
                /* Remove the '[' from stack. */
                if (!stringStack.isEmpty() && stringStack.peek() == '[') {
                    stringStack.pop();
                }
                /* Repeat the extracted string 'count' times. */
                String repeated = "";
                for (int j = 0; j < count; j++) {
                    repeated += temp;
                }
                /* Push the repeated result back onto the character stack. */
                for (int j = 0; j < repeated.length(); j++) {
                    stringStack.push(repeated.charAt(j));
                }
            } else if (ch == '[') {
                /*
                 * If the previous character is a digit just push '[',
                 * otherwise this is an implicit "1[...]" repetition.
                 */
                if (i > 0 && Character.isDigit(str.charAt(i - 1))) {
                    stringStack.push(ch);
                } else {
                    stringStack.push(ch);
                    integerStack.push(1);
                }
            } else {
                /* Regular character, push to stack. */
                stringStack.push(ch);
            }
        }
        /* Build the final result from the character stack. */
        String result = "";
        while (!stringStack.isEmpty()) {
            result = stringStack.pop() + result;
        }
        return result;
    }

