    public static int findWays(int m, int n, int x) {
        // `table[i][j]` stores the number of ways to obtain sum `j`
        // using exactly `i` dice.
        int[][] table = new int[n + 1][x + 1];
        // Base case: with one die, you can make sums 1 … min(m, x) in exactly one way.
        for (int j = 1; j <= Math.min(m, x); j++) {
            table[1][j] = 1;
        }
        // Fill the DP table
        for (int i = 2; i <= n; i++) {
            for (int j = 1; j <= x; j++) {
                // Summation over the last die face value `k`
                // Python's range(1, min(m + 1, j)) iterates up to min(m, j - 1)
                // Hence the strict `<` comparison below.
                for (int k = 1; k < Math.min(m + 1, j); k++) {
                    table[i][j] += table[i - 1][j - k];
                }
            }
        }
        return table[n][x];
    }

