    public static int findDiff(int[] arr, int n) {
        // Sort the array
        Arrays.sort(arr);
        int count     = 0;
        int maxCount  = 0;
        int minCount  = n;   // initialize with the highest possible value
        // Traverse the array and track lengths of consecutive equal elements
        for (int i = 0; i < n - 1; i++) {
            if (arr[i] == arr[i + 1]) {
                count++;               // increment if current and next are equal
                continue;              // move to the next pair
            } else {
                // Update max and min counts
                maxCount = Math.max(maxCount, count);
                minCount = Math.min(minCount, count);
                count = 0;             // reset count for the next group
            }
        }
        // Difference between maximum and minimum counts
        return maxCount - minCount;
    }

