    public static long discreteLogarithm(long a, long b, long m) {
        long n = (long) (Math.sqrt(m) + 1);
        /* a^n (mod m) */
        long an = 1;
        for (long i = 0; i < n; i++) {
            an = (an * a) % m;
        }
        /* Giant-steps: store (a^{n·i}  mod m) → i */
        long[] value = new long[(int) m];           // initialized with zeros
        long cur = an;
        for (long i = 1; i <= n; i++) {
            if (value[(int) cur] == 0) {            // avoid overwriting first occurrence
                value[(int) cur] = i;
            }
            cur = (cur * an) % m;
        }
        /* Baby-steps and lookup */
        cur = b;
        for (long i = 0; i <= n; i++) {
            if (value[(int) cur] > 0) {
                long ans = value[(int) cur] * n - i;
                if (ans < m) {                      // found a valid answer
                    return ans;
                }
            }
            cur = (cur * a) % m;
        }
        return -1;                                  // no solution found
    }

