    public static String longDivision(String number, int divisor) {
        // Result builder
        StringBuilder ans = new StringBuilder();
        // Index pointing to the current digit of `number`
        int idx = 0;
        // Current portion of the number we are working with
        int temp = number.charAt(idx) - '0';
        /* 
         * Find the first prefix of `number` that is >= divisor.  
         * Until then keep appending digits.
         */
        while (temp < divisor && idx + 1 < number.length()) {
            idx++;
            temp = temp * 10 + (number.charAt(idx) - '0');
        }
        /*
         * Main division loop – emulates the long-division algorithm.
         * The Python original runs while len(number) > idx, then accesses idx+1
         * inside the loop body, so effectively it iterates until idx < len-1.
         */
        while (idx < number.length() - 1) {
            // Append current quotient digit
            ans.append((char) ((temp / divisor) + '0'));
            // Bring down the next digit
            temp = (temp % divisor) * 10 + (number.charAt(idx + 1) - '0');
            idx++;
        }
        // Append the final quotient digit
        ans.append((char) ((temp / divisor) + '0'));
        // If quotient is empty, the result is zero
        if (ans.length() == 0) {
            return "0";
        }
        return ans.toString();
    }

