    public static int eggDrop(int n, int k) {
        // eggFloor[i][j] will hold the minimum number of trials needed for
        // i eggs and j floors.
        int[][] eggFloor = new int[n + 1][k + 1];
        // Base cases:
        // 0 trial for 0 floor, 1 trial for 1 floor
        for (int i = 1; i <= n; i++) {
            eggFloor[i][0] = 0;
            eggFloor[i][1] = 1;
        }
        // We always need j trials for 1 egg and j floors
        for (int j = 1; j <= k; j++) {
            eggFloor[1][j] = j;
        }
        // Fill the rest of the table in bottom-up manner
        for (int i = 2; i <= n; i++) {
            for (int j = 2; j <= k; j++) {
                eggFloor[i][j] = Integer.MAX_VALUE;
                // Consider dropping an egg from each floor x
                for (int x = 1; x <= j; x++) {
                    int res = 1 + Math.max(eggFloor[i - 1][x - 1],  // Egg breaks
                                           eggFloor[i][j - x]);     // Egg survives
                    if (res < eggFloor[i][j]) {
                        eggFloor[i][j] = res;
                    }
                }
            }
        }
        return eggFloor[n][k];
    }

