    public static int minPalPartion(String str) {
        int n = str.length();
        if (n == 0) {
            return 0;
        }
        int[][] C = new int[n][n];       // Minimum cuts
        boolean[][] P = new boolean[n][n]; // Palindrome truth table
        // All substrings of length 1 are palindromes
        for (int i = 0; i < n; i++) {
            P[i][i] = true;
            C[i][i] = 0;
        }
        // L is substring length
        for (int L = 2; L <= n; L++) {
            for (int i = 0; i <= n - L; i++) {
                int j = i + L - 1;
                if (L == 2) {
                    P[i][j] = (str.charAt(i) == str.charAt(j));
                } else {
                    P[i][j] = (str.charAt(i) == str.charAt(j)) && P[i + 1][j - 1];
                }
                if (P[i][j]) {
                    C[i][j] = 0;
                } else {
                    C[i][j] = Integer.MAX_VALUE;
                    for (int k = i; k < j; k++) {
                        int cuts = C[i][k] + C[k + 1][j] + 1;
                        if (cuts < C[i][j]) {
                            C[i][j] = cuts;
                        }
                    }
                }
            }
        }
        return C[0][n - 1];
    }

