    public static int findMinInsertions(String str, int l, int h) {
        // If the current window is invalid
        if (l > h) {
            return Integer.MAX_VALUE;
        }
        // If there is only one character
        if (l == h) {
            return 0;
        }
        // If there are two characters and both are the same
        if (l == h - 1) {
            return (str.charAt(l) == str.charAt(h)) ? 0 : 1;
        }
        // If characters at current positions match, move inward
        if (str.charAt(l) == str.charAt(h)) {
            return findMinInsertions(str, l + 1, h - 1);
        }
        // If characters don’t match, consider both possibilities
        return Math.min(
                findMinInsertions(str, l, h - 1),
                findMinInsertions(str, l + 1, h)
        ) + 1;
    }

