        int[][] T = new int[n][n];   // T[i][j] -> #ways expression i..j is TRUE
        int[][] F = new int[n][n];   // F[i][j] -> #ways expression i..j is FALSE
        /* Initialize the diagonal (sub-expressions of length 1) */
        for (int i = 0; i < n; i++) {
            char ch = symbols.charAt(i);
            T[i][i] = (ch == 'T') ? 1 : 0;
            F[i][i] = (ch == 'F') ? 1 : 0;
        }
        /* gap = current sub-expression length – 1 */
        for (int gap = 1; gap < n; gap++) {
            for (int i = 0, j = gap; j < n; i++, j++) {   // (i, j) is sub-expression bounds
                T[i][j] = 0;
                F[i][j] = 0;
                /* Partition the expression at every possible operator k */
                for (int g = 0; g < gap; g++) {
                    int k = i + g;            // current operator index
                    int tik = T[i][k] + F[i][k];      // #ways left  side can be either T or F
                    int tkj = T[k + 1][j] + F[k + 1][j]; // #ways right side can be either T or F
                    char op = operators.charAt(k);
                    if (op == '&') {
                        T[i][j] += T[i][k] * T[k + 1][j];
                        F[i][j] += tik * tkj - T[i][k] * T[k + 1][j];
                    } else if (op == '|') {
                        F[i][j] += F[i][k] * F[k + 1][j];
                        T[i][j] += tik * tkj - F[i][k] * F[k + 1][j];
                    } else if (op == '^') {
                        T[i][j] += F[i][k] * T[k + 1][j] + T[i][k] * F[k + 1][j];
                        F[i][j] += T[i][k] * T[k + 1][j] + F[i][k] * F[k + 1][j];
                    }
                }
            }
        }
        return T[0][n - 1];
    }

