    public static boolean findDuplicateParenthesis(String expression) {
        Stack<Character> stack = new Stack<>();
        for (char ch : expression.toCharArray()) {
            // When we encounter a closing parenthesis
            if (ch == ')') {
                int elementsInside = 0;
                // Pop the first element (top of the stack)
                char top = stack.pop();
                // Count the number of characters inside the current "()"
                while (top != '(') {
                    elementsInside++;
                    top = stack.pop();
                }
                // If no meaningful element was present between "(", ")"
                // then we found duplicate (redundant) parentheses
                if (elementsInside < 1) {
                    return true;
                }
            } else {
                // Push all other characters, including opening parenthesis
                stack.push(ch);
            }
        }
        // No duplicates found
        return false;
    }

