    public static long maxPrimeFactors(long n) {
        long maxPrime = -1;
        // Divide n by 2 until it becomes odd
        while (n % 2 == 0) {
            maxPrime = 2;
            n >>= 1;          // equivalent to n = n / 2
        }
        // n is now odd.  Start checking from 3, skip even numbers.
        for (long i = 3; i <= Math.sqrt(n); i += 2) {
            // While i divides n, store i and divide n
            while (n % i == 0) {
                maxPrime = i;
                n /= i;
            }
        }
        // This condition is to handle the case when n is a prime
        // number greater than 2.
        if (n > 2) {
            maxPrime = n;
        }
        return maxPrime;
    }

