    public static int findMaxAverage(int[] arr, int n, int k) {
        // If the window size is larger than the array, no solution exists
        if (k > n) {
            return -1;
        }
        // Prefix sum array
        int[] csum = new int[n];
        csum[0] = arr[0];
        for (int i = 1; i < n; i++) {
            csum[i] = csum[i - 1] + arr[i];
        }
        // Initialize maximum sum for the first window
        int maxSum = csum[k - 1];
        int maxEndIndex = k - 1;
        // Slide the window through the array
        for (int i = k; i < n; i++) {
            int currentSum = csum[i] - csum[i - k];
            if (currentSum > maxSum) {
                maxSum = currentSum;
                maxEndIndex = i;
            }
        }
        // Starting index of the sub-array with the maximum sum
        return maxEndIndex - k + 1;
    }

