    public static int maxSum(int[] stack1, int[] stack2, int[] stack3) {
        int n1 = stack1.length;
        int n2 = stack2.length;
        int n3 = stack3.length;
        int sum1 = 0, sum2 = 0, sum3 = 0;
        // Calculate initial sums of all three stacks
        for (int v : stack1) sum1 += v;
        for (int v : stack2) sum2 += v;
        for (int v : stack3) sum3 += v;
        int top1 = 0, top2 = 0, top3 = 0;
        // Keep removing elements from the stack(s) with the largest sum
        while (true) {
            // If any stack is exhausted, equal sum cannot be achieved
            if (top1 == n1 || top2 == n2 || top3 == n3) {
                return 0;
            }
            // If sums are already equal, return the sum (answer)
            if (sum1 == sum2 && sum2 == sum3) {
                return sum1;
            }
            // Remove element from the stack that currently has the largest sum
            if (sum1 >= sum2 && sum1 >= sum3) {
                sum1 -= stack1[top1++];
            } else if (sum2 >= sum1 && sum2 >= sum3) {
                sum2 -= stack2[top2++];
            } else { // sum3 is the largest (or tied)
                sum3 -= stack3[top3++];
            }
        }
