        // If there is only one element left
        if (high == low) {
            return arr[low];
        }
        int mid = (low + high) / 2;
        // Check if mid+1 is the minimum element
        if (mid < high && arr[mid + 1] < arr[mid]) {
            return arr[mid + 1];
