        // Check if mid itself is the minimum element
        if (mid > low && arr[mid] < arr[mid - 1]) {
            return arr[mid];
        }
        // Decide whether to search the left half or the right half
        if (arr[high] > arr[mid]) {
            return findMin(arr, low, mid - 1);
        } else {
            return findMin(arr, mid + 1, high);
        }
    }

