    public static boolean isRectangle(int[][] matrix) {
        if (matrix == null || matrix.length == 0) {
            return false;
        }
        int rows    = matrix.length;
        int columns = matrix[0].length;
        // table maps a column index to the set of columns that have already
        // appeared together with it (as 1-1 pairs) in a previous row.
        Map<Integer, Set<Integer>> table = new HashMap<>();
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < columns - 1; j++) {
                if (matrix[i][j] != 1) continue;          // skip if left corner is not 1
                for (int k = j + 1; k < columns; k++) {
                    if (matrix[i][k] != 1) continue;      // skip if right corner is not 1
                    // If this pair of columns has been seen before in some
                    // previous row, we have found a rectangle.
                    if (table.containsKey(j) && table.get(j).contains(k)) return true;
                    if (table.containsKey(k) && table.get(k).contains(j)) return true;
                    // Otherwise, remember that columns (j,k) form a pair in this row.
                    table.computeIfAbsent(j, key -> new HashSet<>()).add(k);
                    table.computeIfAbsent(k, key -> new HashSet<>()).add(j);
                }
            }
        }
        return false;
    }

