    public static long sumOfFactors(long n) {
        // If n is odd, return 0 immediately
        if (n % 2 != 0) {
            return 0;
        }
        long result = 1;
        // The upper limit is fixed using the initial value of n,
        // mirroring Python's range behaviour.
