        if (n >= 9) {
            return "-1";
        }
        int[] result = new int[n + 1];   // Stores the digits of the answer
        int count = 1;                   // Next smallest unused digit
        for (int i = 0; i <= n; i++) {
            // Whenever we reach an 'I' or the end of the pattern,
            // we fill digits backwards as required.
            if (i == n || seq.charAt(i) == 'I') {
                for (int j = i - 1; j >= -1; j--) {
                    result[j + 1] = count;
                    count++;
                    // Stop if the previous pattern character was 'I'
                    if (j >= 0 && seq.charAt(j) == 'I') {
                        break;
                    }
                }
            }
        }
        // Convert the result array to a string
        StringBuilder sb = new StringBuilder();
        for (int digit : result) {
            sb.append(digit);
        }
        return sb.toString();
