    public static int pairsInSortedRotated(int[] arr, int n, int x) {
        // 1. Find the index of the largest element (pivot).
        int i;
        for (i = 0; i < n - 1; i++) {
            if (arr[i] > arr[i + 1]) {
                break;
            }
        }
        // 2. Initialize left and right pointers.
        int l = (i + 1) % n;  // index of smallest element
        int r = i;            // index of largest element
        int cnt = 0;
        // 3. Two‐pointer traversal on the rotated array.
        while (l != r) {
            int currentSum = arr[l] + arr[r];
            // Pair found
            if (currentSum == x) {
                cnt++;
                // If pointers are going to overlap, break (all pairs checked).
                if (l == (r - 1 + n) % n) {
                    return cnt;
                }
                l = (l + 1) % n;
                r = (r - 1 + n) % n;
            }
            // Move left pointer forward to increase sum.
            else if (currentSum < x) {
                l = (l + 1) % n;
            }
            // Move right pointer backward to decrease sum.
            else {
                r = (r - 1 + n) % n;
            }
        }
        return cnt;
    }

