    public static boolean isSubSeqDivisible(String str) {
        int n = str.length();
        /* dp[i][r] == 1  →  there exists a subsequence using the first i characters
           whose value gives remainder r (mod 8).                        */
        int[][] dp = new int[n + 1][8];
        /* Convert characters to integer digits (1-based indexing like the Python code). */
        int[] arr = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            arr[i] = str.charAt(i - 1) - '0';
        }
        /* Fill the DP table. */
        for (int i = 1; i <= n; i++) {
            /* Subsequence consisting solely of the i-th digit. */
            dp[i][arr[i] % 8] = 1;
            /* Extend or ignore previous subsequences. */
            for (int j = 0; j < 8; j++) {
                /* Append current digit to a previous subsequence giving remainder j. */
                int nextRemainder = (j * 10 + arr[i]) % 8;
                if (dp[i - 1][j] > dp[i][nextRemainder]) {
                    dp[i][nextRemainder] = dp[i - 1][j];
                }
                /* Or just carry over the previous subsequence unchanged. */
                if (dp[i - 1][j] > dp[i][j]) {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }
        /* Check if any prefix produced remainder 0 (i.e., divisible by 8). */
        for (int i = 1; i <= n; i++) {
            if (dp[i][0] == 1) {
                return true;
            }
        }
        return false;
    }

