    public static int exactPrimeFactorCount(long n) {
        int count = 0;
        // Handle the factor 2 separately
        if (n % 2 == 0) {
            count++;
            while (n % 2 == 0) {
                n /= 2;
            }
        }
        // Check odd factors starting from 3
        for (long i = 3; i <= Math.sqrt(n); i += 2) {
            if (n % i == 0) {
                count++;
                while (n % i == 0) {
                    n /= i;
                }
            }
        }
        // If n is still greater than 2, it is prime
        if (n > 2) {
            count++;
        }
        return count;
    }

