    public static int findOptimal(int N) {
        // Base cases: for N up to 6, the best we can do is press 'A' N times
        if (N <= 6) {
            return N;
        }
        // screen[i] will store the optimal result for (i + 1) key presses
        int[] screen = new int[N];
        // For the first six key presses, the optimal result is simply i + 1
        for (int n = 1; n <= 6; n++) {
            screen[n - 1] = n;
        }
        // Compute optimal values for key presses from 7 to N
        for (int n = 7; n <= N; n++) {
            // Option 1: Copy all (Ctrl-A, Ctrl-C) at position (n-3) and paste twice
            int option1 = 2 * screen[n - 4];
            // Option 2: Copy all at position (n-4) and paste three times
            int option2 = 3 * screen[n - 5];
            // Option 3: Copy all at position (n-5) and paste four times
            int option3 = 4 * screen[n - 6];
            // Choose the maximum of the three options
            screen[n - 1] = Math.max(option1, Math.max(option2, option3));
        }
        // The result for N key presses is stored at screen[N - 1]
        return screen[N - 1];
    }

