                int subArraySum = prefix[j] - prefix[i - 1];
                if (minHeap.size() < k) {
                    // Heap not full: just add the current sum
                    minHeap.offer(subArraySum);
                } else if (minHeap.peek() < subArraySum) {
                    // Current sum is larger than the smallest in heap: replace it
                    minHeap.poll();
                    minHeap.offer(subArraySum);
                }
                // else: current sum is not large enough, ignore it
            }
