    public static int lengthOfLongestAP(int[] arr, int n) {
        // An AP must have at least two elements
        if (n <= 2) {
            return n;
        }
        // L[i][j] stores LLAP with arr[i] and arr[j] as first two elements
        int[][] L = new int[n][n];
