        // The last column of every row is always 2
        for (int i = 0; i < n; i++) {
            L[i][n - 1] = 2;
        }
        // Traverse the remaining columns starting from the second-last
        for (int j = n - 2; j >= 1; j--) {
            int i = j - 1;
            int k = j + 1;
            while (i >= 0 && k <= n - 1) {
                if (arr[i] + arr[k] < 2 * arr[j]) {
                    k++;
                } else if (arr[i] + arr[k] > 2 * arr[j]) {
                    // No valid k for this i and j
                    L[i][j] = 2;
                    i--;
                } else {
                    // Found i, j, k that form an AP
                    L[i][j] = L[j][k] + 1;
                    llap = Math.max(llap, L[i][j]);
                    i--;
                    k++;
                }
            }
            // If any i's are left, set LLAP for them (length 2)
            while (i >= 0) {
                L[i][j] = 2;
                i--;
            }
        }
        return llap;
    }

