    public static String maximumPalinUsingKChanges(String str, int k) {
        int n = str.length();
        char[] palin = str.toCharArray();     // working copy that will be transformed
        /* ------------------------------------------------------------------
         * 1st pass : make the string a palindrome, using the fewest changes
         * ------------------------------------------------------------------ */
        int l = 0;
        int r = n - 1;
        while (l <= r) {
            if (str.charAt(l) != str.charAt(r)) {
                // Replace both by the larger of the two characters
                char maxChar = (char) Math.max(str.charAt(l), str.charAt(r));
                palin[l] = maxChar;
                palin[r] = maxChar;
                k--;                         // one change consumed
            }
            l++;
            r--;
        }
        if (k < 0) {                         // not enough changes to even form a palindrome
            return "Not possible";
        }
        /* ------------------------------------------------------------------
         * 2nd pass : try to maximize the palindrome's value (set digits to '9')
         * ------------------------------------------------------------------ */
        l = 0;
        r = n - 1;
        while (l <= r) {
            // Middle character in an odd-length string
            if (l == r) {
                if (k > 0) {
                    palin[l] = '9';
                }
            }
            // If this symmetric pair is not already '9'
            if (palin[l] < '9') {
                /* Case 1: neither position was changed in the 1st pass
                 * (needs two available changes: one for each side)        */
                if (k >= 2 && palin[l] == str.charAt(l) && palin[r] == str.charAt(r)) {
                    k -= 1;                      // note: original algorithm decrements by 1
                    palin[l] = palin[r] = '9';
                }
                /* Case 2: at least one of the two positions was already
                 * modified in the first pass (only one extra change needed) */
                else if (k >= 1 && (palin[l] != str.charAt(l) || palin[r] != str.charAt(r))) {
                    k -= 1;
                    palin[l] = palin[r] = '9';
                }
            }
            l++;
            r--;
        }
        return new String(palin);
    }

