    public static int findMaxVal(int[] arr, int n, int num, int maxLimit) {
        // dp[ind][val] == true  ⇨  we can reach “val” with elements 0…ind
        boolean[][] dp = new boolean[n][maxLimit + 1];
        for (int ind = 0; ind < n; ind++) {
            for (int val = 0; val <= maxLimit; val++) {
                if (ind == 0) {
                    // Base case – initialise the first row
                    if (num - arr[ind] == val || num + arr[ind] == val) {
                        dp[ind][val] = true;
                    }
                } else {
                    boolean reachable = false;
                    // Case: take (val - arr[ind]) from previous row
                    if (val - arr[ind] >= 0 && dp[ind - 1][val - arr[ind]]) {
                        reachable = true;
                    }
                    // Case: take (val + arr[ind]) from previous row
                    if (val + arr[ind] <= maxLimit && dp[ind - 1][val + arr[ind]]) {
                        reachable = true;
                    }
                    dp[ind][val] = reachable;
                }
            }
        }
        // Find the maximum reachable value from the last row
        for (int val = maxLimit; val >= 0; val--) {
            if (dp[n - 1][val]) {
                return val;
            }
        }
        return -1;
    }

