static     public int largestSumOfAverages(int[] A, int K) {
        int n = A.length;
        double[] preSum = new double[n + 1];
        // Build prefix sum array (as double to avoid casting later)
        for (int i = 0; i < n; i++) {
            preSum[i + 1] = preSum[i] + A[i];
        }
        // dp[i] stores the best (largest) possible sum of averages
        // for sub-array starting at index i
        double[] dp = new double[n];
        // Base: one single group starting at i and running to the end
        for (int i = 0; i < n; i++) {
            dp[i] = (preSum[n] - preSum[i]) / (n - i);
        }
        // Up to K-1 additional cuts (total groups ≤ K)
        for (int k = 0; k < K - 1; k++) {
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    double avg = (preSum[j] - preSum[i]) / (j - i);
                    dp[i] = Math.max(dp[i], avg + dp[j]);
                }
            }
        }
        // Truncate to int as in the original Python code (int() cast)
        return (int) dp[0];
    }

