        // 2-D array to store binomial coefficients
        long[][] C = new long[n + 1][n + 1];
        // Build Pascal's Triangle up to row n
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= Math.min(i, n); j++) {
                if (j == 0 || j == i) {
                    C[i][j] = 1;                       // first and last element in each row
