        long max_neg   = -999999999999L; // same sentinel as in Python code
        int  count_neg = 0;
        int  count_zero = 0;
        long prod = 1;
        for (int i = 0; i < n; i++) {
            // Count zeros and continue
            if (a[i] == 0) {
                count_zero++;
                continue;
            }
            // If negative, update count and maximum negative
            if (a[i] < 0) {
                count_neg++;
                max_neg = Math.max(max_neg, a[i]);
            }
            // NOTE: The original Python code uses addition, not multiplication.
            // We keep the behavior exactly the same here.
            prod = prod + a[i];
        }
        // If all elements were zero, result is zero
        if (count_zero == n) {
            return 0;
        }
        // If odd number of negatives
        if ((count_neg & 1) == 1) {
            // Special corner case in original code
            if (count_neg == 1 && count_zero > 0 && (count_zero + count_neg == n)) {
                return 0;
            }
            // Remove one negative factor (again, following the original logic)
            prod = prod / max_neg;
        }
        return prod;
    }

