    public static int maxProfit(int[] price, int n) {
        if (price == null || n == 0) {
            return 0;
        }
        int[] profit = new int[n];
        /* -------- First pass (right → left) --------
           profit[i] will hold the maximum profit that can be obtained
           with ONE transaction in sub-array price[i … n-1]              */
        int maxPrice = price[n - 1];
        for (int i = n - 2; i > 0; i--) {           // i goes from n-2 down to 1
            if (price[i] > maxPrice) {
                maxPrice = price[i];
            }
            profit[i] = Math.max(profit[i + 1], maxPrice - price[i]);
        }
        /* -------- Second pass (left → right) --------
           Now update profit[i] so it represents the maximum profit with
           at most TWO transactions in price[0 … i]                       */
        int minPrice = price[0];
        for (int i = 1; i < n; i++) {
            if (price[i] < minPrice) {
                minPrice = price[i];
            }
            profit[i] = Math.max(
                            profit[i - 1],                 // no transaction on day i
                            profit[i] + (price[i] - minPrice) // second transaction ends on day i
                         );
        }
        return profit[n - 1];
    }

