        /* ---------- backward pass (Kadane from right) ---------- */
        curMax = arr[n - 1];
        maxSoFar = curMax;
        bw[n - 1] = curMax;
        for (int i = n - 2; i >= 0; i--) {
            curMax = Math.max(arr[i], curMax + arr[i]);
            maxSoFar = Math.max(maxSoFar, curMax);
            bw[i] = curMax;
