    public static int getMinDiff(int[] arr, int n, int k) {
        if (n == 1) {
            return 0;
        }
        // Sort the array so we can work with its smallest and largest values easily
        Arrays.sort(arr);
        // Initial difference without any modification
        int ans = arr[n - 1] - arr[0];
        // Tentative small and big values after modification
        int small = arr[0] + k;
        int big   = arr[n - 1] - k;
        // Ensure small <= big
        if (small > big) {
            int temp = small;
            small = big;
            big = temp;
        }
        // Try to minimize the difference by adjusting the middle elements
        for (int i = 1; i < n - 1; i++) {
            int subtract = arr[i] - k;
            int add      = arr[i] + k;
            // If the current element adjustment keeps the range unchanged, skip
            if (subtract >= small || add <= big) {
                continue;
            }
            // Choose to adjust small or big based on which yields a smaller range
            if (big - subtract <= add - small) {
                small = subtract;
            } else {
                big = add;
            }
        }
        return Math.min(ans, big - small);
    }

