    public static int solve(String X, String Y,
                            int l, int r, int k,
                            int[][][] dp) {
        // Base cases
        if (k == 0)                          // no more pairs required
            return 0;
        if (l < 0 || r < 0)                  // ran out of characters
            return INF;
        // Memoised result
        if (dp[l][r][k] != -1)
            return dp[l][r][k];
        // Cost of pairing characters X[l] and Y[r]
        int cost = ((X.charAt(l) - 'a') ^ (Y.charAt(r) - 'a'));
        // Three possibilities (pick both, skip X[l], skip Y[r])
        int takeBoth  = cost + solve(X, Y, l - 1, r - 1, k - 1, dp);
        int skipLeft  = solve(X, Y, l - 1, r,     k,     dp);
        int skipRight = solve(X, Y, l,     r - 1, k,     dp);
        // Memoise and return the minimum
        dp[l][r][k] = Math.min(takeBoth, Math.min(skipLeft, skipRight));
        return dp[l][r][k];
    }

