    public static int MinimumCost(int[] cost, int n, int W) {
        // 1.  Collect only the available packets
        List<Integer> val = new ArrayList<>();
        List<Integer> wt  = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if (cost[i] != -1) {          // packet is available
                val.add(cost[i]);         // its cost
                wt.add(i + 1);            // its weight (index + 1)
            }
        }
        n = val.size();                   // update n to actual number of usable packets
        // 2.  DP table : (n + 1) × (W + 1)
        int[][] minCost = new int[n + 1][W + 1];
        // 3.  Initialize first row to INF
        for (int j = 0; j <= W; j++) {
            minCost[0][j] = INF;
        }
        // 4.  First column (weight 0) is 0 for all i ≥ 1
        for (int i = 1; i <= n; i++) {
            minCost[i][0] = 0;
        }
        // 5.  Fill the DP table
        for (int i = 1; i <= n; i++) {
            int currentWt  = wt.get(i - 1);
            int currentVal = val.get(i - 1);
            for (int j = 1; j <= W; j++) {
                if (currentWt > j) {
                    // Cannot take this packet
                    minCost[i][j] = minCost[i - 1][j];
                } else {
                    // Either skip it, or take it (unbounded -> stay on row i)
                    int skip    = minCost[i - 1][j];
                    int take    = minCost[i][j - currentWt] + currentVal;
                    minCost[i][j] = Math.min(skip, take);
                }
            }
        }
        // 6.  Answer
        return (minCost[n][W] == INF) ? -1 : minCost[n][W];
    }

