        // If array contains only one element, return it.
        if (n == 1) {
            return a[0];
        }
        int  maxNeg   = Integer.MIN_VALUE; // largest (closest-to-zero) negative
        int  minPos   = Integer.MAX_VALUE; // smallest positive
        int  countNeg = 0;                 // number of negative values
        int  countZero= 0;                 // number of zeros
        long prod     = 1;                 // product of all non-zero elements
        for (int i = 0; i < n; i++) {
            // Skip zeros but keep their count
            if (a[i] == 0) {
