    public static long nonFibonacci(long n) {
        long prevPrev = 1; // F(1)
        long prev     = 2; // F(2)
        long curr     = 3; // F(3)
        // Move forward through the Fibonacci sequence until we have
        // passed at least n non-Fibonacci numbers.
        while (n > 0) {
            prevPrev = prev;
            prev     = curr;
            curr     = prevPrev + prev;        // next Fibonacci number
            n -= (curr - prev - 1);            // count of non-Fibs between prev and curr
        }
        // We went one step too far; adjust n back into the current gap
        n += (curr - prev - 1);
        // The answer is n positions after 'prev'
        return prev + n;
    }

