    public static long answer(int n) {
        // dp[i][j] – how many i-digit numbers end with digit j
        long[][] dp = new long[n + 1][10];
        // Base case: a single-digit number can be any of the ten digits
        if (n == 1) {
            return 10;
        }
        // Initialize 1-digit counts
        for (int j = 0; j < 10; j++) {
            dp[1][j] = 1;
        }
        // Fill the DP table
        for (int i = 2; i <= n; i++) {
            for (int j = 0; j < 10; j++) {
                if (j == 0) {
                    dp[i][j] = dp[i - 1][j + 1];
                } else if (j == 9) {
                    dp[i][j] = dp[i - 1][j - 1];
                } else {
                    dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j + 1];
                }
            }
        }
        // Sum over all n-digit numbers that don’t start with 0
        long sum = 0;
        for (int j = 1; j < 10; j++) {
            sum += dp[n][j];
        }
        return sum;
    }

