    public static long countDivisibleSubseq(String str, int n) {
        int len = str.length();
        long[][] dp = new long[len][n];
        // Handle the first character separately
        int firstDigit = str.charAt(0) - '0';
        dp[0][firstDigit % n]++;
        // Fill dp table
        for (int i = 1; i < len; i++) {
            int digit = str.charAt(i) - '0';
            // Subsequence consisting of the current single digit
            dp[i][digit % n]++;
            for (int rem = 0; rem < n; rem++) {
                // Copy all previous subsequences (skip current digit)
                dp[i][rem] += dp[i - 1][rem];
                // Append current digit to all previous subsequences
                int newRem = (rem * 10 + digit) % n;
                dp[i][newRem] += dp[i - 1][rem];
            }
        }
        // Result is the count of subsequences whose remainder is 0
        return dp[len - 1][0];
    }

