                factorCount[i] = 1;         // prime numbers have exactly one prime factor (themselves)
                for (int j = i * 2; j <= n; j += i) {
                    factorCount[j] += 1;    // i is a distinct prime factor of j
                    prime[j] = false;       // mark j as composite
                }
