    public static double maxAverageOfPath(int[][] cost) {
        int N = cost.length;
        if (N == 0) {
            throw new IllegalArgumentException("Cost matrix must be non-empty");
        }
        // dp[i][j] stores the maximum total cost achievable to reach (i, j)
        int[][] dp = new int[N][N];
        dp[0][0] = cost[0][0];
        // First column (can only come from above)
        for (int i = 1; i < N; i++) {
            dp[i][0] = dp[i - 1][0] + cost[i][0];
        }
        // First row (can only come from the left)
        for (int j = 1; j < N; j++) {
            dp[0][j] = dp[0][j - 1] + cost[0][j];
        }
        // Fill the rest of the table
        for (int i = 1; i < N; i++) {
            for (int j = 1; j < N; j++) {
                dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j];
            }
        }
        // Total number of cells in the path from (0,0) to (N-1,N-1): 2N - 1
        return dp[N - 1][N - 1] / (double) (2 * N - 1);
    }

