    public static void rearrange(int[] a, int size) {
        int positive = 0; // next even index expected to hold a positive number
        int negative = 1; // next odd  index expected to hold a negative number
        while (true) {
            // Move `positive` forward to the next misplaced element (negative value in even slot)
            while (positive < size && a[positive] >= 0) {
                positive += 2;
            }
            // Move `negative` forward to the next misplaced element (positive value in odd slot)
            while (negative < size && a[negative] <= 0) {
                negative += 2;
            }
            // If both indices are within range, swap the misplaced elements
            if (positive < size && negative < size) {
                int temp = a[positive];
                a[positive] = a[negative];
                a[negative] = temp;
            } else {
                // No more valid swaps possible
                break;
            }
        }
    }

