    public static void antiSpiralTraversal(int[][] matrix) {
        if (matrix == null || matrix.length == 0 || matrix[0].length == 0) {
            return;                       // nothing to do
        }
        int m = matrix.length - 1;        // last row index
        int n = matrix[0].length - 1;     // last column index
        int k = 0;                        // first row index
        int l = 0;                        // first column index
        Stack<Integer> stk = new Stack<>();
        // Collect elements in clockwise spiral order
        while (k <= m && l <= n) {
            // Traverse the first row (left → right)
            for (int i = l; i <= n; i++) {
                stk.push(matrix[k][i]);
            }
            k++;
            // Traverse the last column (top → bottom)
            for (int i = k; i <= m; i++) {
                stk.push(matrix[i][n]);
            }
            n--;
            // Traverse the last row (right → left) if rows remain
            if (k <= m) {
                for (int i = n; i >= l; i--) {
                    stk.push(matrix[m][i]);
                }
                m--;
            }
            // Traverse the first column (bottom → top) if columns remain
            if (l <= n) {
                for (int i = m; i >= k; i--) {
                    stk.push(matrix[i][l]);
                }
                l++;
            }
        }
        // Pop the stack to print in anti-spiral order
        while (!stk.isEmpty()) {
            System.out.print(stk.pop() + " ");
        }
    }

