    public static long solve(long[][] dp, long[] a, int low, int high, int turn) {
        // Base case: only one element left
        if (low == high) {
            return a[low] * turn;
        }
        // Return cached value if already computed
        if (dp[low][high] != 0) {
            return dp[low][high];
        }
        // Choose max between taking from the left or right end
        long takeLeft  = a[low]  * turn + solve(dp, a, low + 1, high,     turn + 1);
        long takeRight = a[high] * turn + solve(dp, a, low,     high - 1, turn + 1);
        dp[low][high] = Math.max(takeLeft, takeRight);
        return dp[low][high];
    }

