    public static String simplify(String str) {
        int len = str.length();
        StringBuilder result = new StringBuilder(len);
        // stack keeps track of the current sign context
        // 0 → keep the sign, 1 → flip the sign
        Stack<Integer> stack = new Stack<>();
        stack.push(0);          // initial context: no flip
        for (int i = 0; i < len; i++) {
            char ch = str.charAt(i);
            if (ch == '+') {
                // decide the actual sign based on current context
                result.append(stack.peek() == 1 ? '-' : '+');
            } else if (ch == '-') {
                // decide the actual sign based on current context
                result.append(stack.peek() == 1 ? '+' : '-');
            } else if (ch == '(' && i > 0) {
                // entering a parenthesis ‒ push new context
                char prev = str.charAt(i - 1);
                if (prev == '-') {
                    // flip whatever the current context is
                    stack.push(stack.peek() == 1 ? 0 : 1);
                } else if (prev == '+') {
                    // inherit the current context
                    stack.push(stack.peek());
                }
            } else if (ch == ')') {
                // leaving a parenthesis ‒ pop context
                if (!stack.isEmpty()) {
                    stack.pop();
                }
            } else {
                // regular character (variable, digit, etc.)
                result.append(ch);
            }
        }
        return result.toString();
    }

