                // Update the longest valid window found so far.
                if (longestStart == -1 || (end - start) > (longestEnd - longestStart)) {
                    longestStart = start;
                    longestEnd   = end;
                }
            }
        }
        // If no valid sub-array was found, we must remove all elements.
        if (longestStart == -1) {
            return n;
        }
