    public static int gcd(int a, int b) {
        // Handle zero cases
        if (a == 0) {
            return b;
        }
        if (b == 0) {
            return a;
        }
        // k counts the number of common factors of 2
        int k = 0;
        // Remove common factors of 2 from both a and b
        while (((a | b) & 1) == 0) {  // while a and b are both even
            a >>= 1;
            b >>= 1;
            k++;
        }
        // Make sure a is odd
        while ((a & 1) == 0) {
            a >>= 1;
        }
        // From here on, a is always odd
        while (b != 0) {
            // Remove all factors of 2 in b — it’s okay because a is odd
            while ((b & 1) == 0) {
                b >>= 1;
            }
            // Now a and b are both odd. Swap so a <= b, then set b = b - a
            if (a > b) {
                int temp = a;
                a = b;
                b = temp;
            }
            b = b - a;  // b is now even
        }
        // Restore common factors of 2
        return a << k;
    }

