    public static int gcd(int a, int b) {
        // base cases
        if (a == b) return a;
        if (a == 0) return b;
        if (b == 0) return a;
        // a is even
        if ((a & 1) == 0) {
            // a even, b odd
            if ((b & 1) == 1) {
                return gcd(a >> 1, b);
            }
            // both even
            return gcd(a >> 1, b >> 1) << 1;
        }
        // a is odd, b is even
        if ((b & 1) == 0) {
            return gcd(a, b >> 1);
        }
        // both odd
        if (a > b) {
            return gcd((a - b) >> 1, b);
        }
        return gcd((b - a) >> 1, a);
    }

