            for (int j = 0; j <= Math.min(i, n); j++) {
                if (j == 0 || j == i) {
                    C[i][j] = 1;                   // Base cases: C(i,0) = C(i,i) = 1
                } else {
                    C[i][j] = C[i - 1][j - 1]      // Recurrence: C(i,j) = C(i-1,j-1) + C(i-1,j)
                             + C[i - 1][j];
                }
            }
        }
        // Sum the elements of the n-th row
        long sum = 0;
        for (int i = 0; i <= n; i++) {
            sum += C[n][i];
        }
        return sum;
    }

