    public static int divSum(int n) {
        int result = 0;
        int limit = (int) Math.sqrt(n);          // highest factor we need to test
        for (int i = 2; i <= limit; i++) {
            if (n % i == 0) {                    // i is a divisor
                if (i == n / i) {                // both divisors are the same (perfect square)
                    result += i;
                } else {                         // add both divisors
                    result += i + n / i;
                }
            }
        }
        // add 1 and n themselves
        return result + n + 1;
    }

