    public static long swapBits(long x, int p1, int p2, int n) {
        // Isolate the n bits starting at p1 and p2.
        long set1 = (x >> p1) & ((1L << n) - 1);
        long set2 = (x >> p2) & ((1L << n) - 1);
        // Compute XOR to identify differing bits.
        long xor = set1 ^ set2;
        // Put the differing bits back to their original positions.
        xor = (xor << p1) | (xor << p2);
        // Toggle the differing bits in the original number.
        return x ^ xor;
    }

