    public static long countTransformation(String a, String b) {
        int n = a.length();
        int m = b.length();
        // Empty target can always be formed in exactly one way
        if (m == 0) {
            return 1L;
        }
        // dp[i][j] = number of ways first (i + 1) chars of b can be formed
        //            using first (j + 1) chars of a
        long[][] dp = new long[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = i; j < n; j++) {          // optimisation: j >= i
                char ca = a.charAt(j);
                char cb = b.charAt(i);
                if (i == 0) {                      // First row
                    if (j == 0) {
                        dp[i][j] = (ca == cb) ? 1 : 0;
                    } else if (ca == cb) {
                        dp[i][j] = dp[i][j - 1] + 1;
                    } else {
                        dp[i][j] = dp[i][j - 1];
                    }
                } else {                           // Remaining rows
                    if (ca == cb) {
                        dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1];
                    } else {
                        dp[i][j] = dp[i][j - 1];
                    }
                }
            }
        }
        return dp[m - 1][n - 1];
    }

