    public static boolean isMultipleOf3(int n) {
        int oddCount = 0;
        int evenCount = 0;
        // Handle negative numbers
        if (n < 0) {
            n = -n;
        }
        // Base cases
        if (n == 0) {
            return true;
        }
        if (n == 1) {
            return false;
        }
        // Count set bits at odd and even positions
        while (n != 0) {
            if ((n & 1) != 0) {        // Bit at position 0 (odd) is set
                oddCount++;
            }
            if ((n & 2) != 0) {        // Bit at position 1 (even) is set
                evenCount++;
            }
            n >>= 2;                   // Shift out two bits
        }
        // Recursive call with the absolute difference
        return isMultipleOf3(Math.abs(oddCount - evenCount));
    }

