    public static long nearestSmallerEqFib(long n) {
        // Handle the trivial cases first.
        if (n == 0 || n == 1) {
            return n;
        }
        long f1 = 0;   // F(k-2)
        long f2 = 1;   // F(k-1)
        long f3 = 1;   // F(k)
        // Move forward until f3 surpasses n.
        while (f3 <= n) {
            f1 = f2;
            f2 = f3;
            f3 = f1 + f2;
        }
        // When the loop exits, f2 is the largest Fibonacci number <= n.
        return f2;
    }
